const useSmoothScroll=()=>{const[s,setS]=useState(0);const t=useRef(0),c=useRef(0),r=useRef(null);useEffect(()=>{const o=()=>{t.current=window.scrollY;};window.addEventListener("scroll",o,{passive:true});const a=()=>{c.current+=(t.current-c.current)*0.08;setS(c.current);r.current=requestAnimationFrame(a);};r.current=requestAnimationFrame(a);return()=>{window.removeEventListener("scroll",o);cancelAnimationFrame(r.current);};},[]);return s;};
const useInView=(th=0.15)=>{const ref=useRef(null);const[v,setV]=useState(false);useEffect(()=>{const el=ref.current;if(!el)return;const obs=new IntersectionObserver(([e])=>{if(e.isIntersecting){setV(true);obs.unobserve(el);}},{threshold:th});obs.observe(el);return()=>obs.disconnect();},[th]);return[ref,v];};
const AI=({children,delay=0,direction="up",style:s})=>{const[ref,v]=useInView(0.1);const t={up:"translateY(60px)",down:"translateY(-60px)",left:"translateX(60px)",right:"translateX(-60px)",scale:"scale(0.9)"};return<div ref={ref} style={{opacity:v?1:0,transform:v?"translate(0) scale(1)":t[direction],transition:`opacity 0.8s cubic-bezier(0.16,1,0.3,1) ${delay}s, transform 0.8s cubic-bezier(0.16,1,0.3,1) ${delay}s`,...s}}>{children}</div>;};
