const MP=()=>{const[at,setAT]=useState(0);const tabs=["One-off","Monthly (trainer+equip)","Monthly (trainer only)"];const d0=[{n:"1:1 Trainer+Equip",s:"Home (45-60min)",p:35000,f:["Personal trainer","Full equipment","Custom workout","Your location"]},{n:"1:1 Trainer Only",s:"Home (45-60min)",p:30000,f:["Personal trainer","Own equipment","Custom workout","Your location"]},{n:"1:1 Trainer Only",s:"Gym (45-60min)",p:25000,f:["Personal trainer","Gym equipment","Custom workout","Meet at gym"]},{n:"Virtual Session",s:"Online (45-60min)",p:25000,f:["Video call","Form correction","Custom workout","Train anywhere"]}];const d1=[{n:"2x/week",s:"8 sessions/mo",p:200000,f:["Trainer","Full equipment","Progress tracking","WhatsApp support"]},{n:"3x/week",s:"12 sessions/mo",p:300000,f:["Trainer","Full equipment","Progress tracking","Nutrition guidance","Priority scheduling"],h:true},{n:"5x/week",s:"20 sessions/mo",p:500000,f:["Trainer","Full equipment","Progress tracking","Nutrition guidance","Dedicated trainer","24/7 WhatsApp"]}];const d2=[{n:"2x/week",s:"8 sessions/mo",p:144000,f:["Trainer","Custom workouts","Progress tracking","WhatsApp support"]},{n:"3x/week",s:"12 sessions/mo",p:216000,f:["Trainer","Custom workouts","Progress tracking","Nutrition guidance","Priority scheduling"],h:true},{n:"5x/week",s:"20 sessions/mo",p:360000,f:["Trainer","Custom workouts","Progress tracking","Nutrition guidance","Dedicated trainer","24/7 WhatsApp"]}];const dd=[d0,d1,d2];return(<PW t="Memberships" st="Choose your plan"><div style={{maxWidth:1000,margin:"0 auto"}}><AI><div style={{display:"flex",gap:0,marginBottom:48,justifyContent:"center",flexWrap:"wrap"}}>{tabs.map((t,i)=><button key={i} onClick={()=>setAT(i)} style={{padding:"12px 24px",background:i===at?"#fff":"transparent",color:i===at?"#000":"rgba(255,255,255,.4)",border:"1px solid",borderColor:i===at?"#fff":"rgba(255,255,255,.1)",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:L,letterSpacing:1}}>{t.toUpperCase()}</button>)}</div></AI><div style={{display:"grid",gridTemplateColumns:`repeat(auto-fit,minmax(${at===0?"200px":"250px"},1fr))`,gap:24}}>{dd[at].map((p,i)=><AI key={`${at}-${i}`} delay={i*.1}><PC {...p}/></AI>)}</div><AI delay={.3}><div style={{textAlign:"center",marginTop:48,padding:24,border:"1px solid rgba(255,255,255,.06)"}}><p style={{color:"rgba(255,255,255,.5)",fontSize:14,fontFamily:L}}>Consultation fee</p><span style={{fontSize:28,fontWeight:700,color:"#fff",fontFamily:F}}>&#8358;{fp(20000)}</span><p style={{fontSize:12,color:"rgba(255,255,255,.25)",marginTop:4,fontFamily:L}}>incl. 7.5% VAT</p></div></AI></div></PW>);};
const PC=({n,s,p,f,h:hl})=>{const[h,setH]=useState(false);const pv=fp(p);return(<div onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)} style={{border:hl?"2px solid #fff":"1px solid rgba(255,255,255,.06)",padding:28,transition:"all .5s",transform:h?"translateY(-8px)":"none",background:h?"rgba(255,255,255,.03)":"transparent",position:"relative",display:"flex",flexDirection:"column"}}>{hl&&<div style={{position:"absolute",top:-12,left:"50%",transform:"translateX(-50%)",background:"#fff",color:"#000",fontSize:11,fontWeight:600,padding:"4px 16px",fontFamily:L}}>POPULAR</div>}<h3 style={{fontSize:17,fontWeight:600,color:"#fff",margin:"0 0 4px",fontFamily:L}}>{n}</h3>{s&&<p style={{fontSize:12,color:"rgba(255,255,255,.35)",margin:"0 0 16px",fontFamily:L}}>{s}</p>}<div style={{margin:"0 0 4px"}}><span style={{fontSize:30,fontWeight:700,color:"#fff",fontFamily:F}}>&#8358;{pv}</span></div><p style={{fontSize:11,color:"rgba(255,255,255,.25)",margin:"0 0 20px",fontFamily:L}}>incl. 7.5% VAT</p><div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:24,flex:1}}>{f.map((x,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:8}}><span style={{color:"#fff",fontSize:12}}>&#10003;</span><span style={{color:"rgba(255,255,255,.45)",fontSize:13,fontFamily:L}}>{x}</span></div>)}</div>{hl?<BP onClick={()=>sPlan(n+(s?" ("+s+")":""),pv)} label="Get started" style={{width:"100%",padding:"12px"}}/>:<BO onClick={()=>sPlan(n+(s?" ("+s+")":""),pv)} label="Get started" full/>}</div>);};

const SP=({cart,setCart})=>{const pr=[{n:"Off-Szn Performance Tee",p:15000,i:"T"},{n:"Off-Szn Training Shorts",p:18000,i:"S"},{n:"Off-Szn Shaker Bottle",p:8000,i:"B"},{n:"Off-Szn Resistance Band Set",p:12000,i:"R"}];const ac=x=>{const e=cart.findIndex(i=>i.name===x.n);if(e>=0){const u=[...cart];u[e].qty+=1;setCart(u);}else setCart([...cart,{name:x.n,price:x.p,qty:1}]);};return(<PW t="Store" st="Gear up for greatness"><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(200px,1fr))",gap:24,maxWidth:900,margin:"0 auto"}}>{pr.map((x,i)=><AI key={i} delay={i*.1}><PrC n={x.n} p={x.p} img={x.i} onAdd={()=>ac(x)}/></AI>)}</div></PW>);};
const PrC=({n,p,img,onAdd})=>{const[h,setH]=useState(false);const[a,setA]=useState(false);return(<div onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)} style={{border:"1px solid",borderColor:h?"rgba(255,255,255,.35)":"rgba(255,255,255,.06)",overflow:"hidden",transition:"all .5s",transform:h?"translateY(-6px)":"none",cursor:"pointer"}}><div style={{height:200,background:"#111",display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{fontSize:48,color:"rgba(255,255,255,.06)",fontWeight:800,transition:"transform .5s",transform:h?"scale(1.2) rotate(-5deg)":"scale(1)"}}>{img}</span></div><div style={{padding:16}}><p style={{fontSize:14,fontWeight:600,color:"#fff",margin:"0 0 4px",fontFamily:L}}>{n}</p><p style={{fontSize:14,color:"rgba(255,255,255,.5)",fontWeight:600,margin:"0 0 2px",fontFamily:L}}>&#8358;{fp(p)}</p><p style={{fontSize:11,color:"rgba(255,255,255,.25)",margin:"0 0 12px",fontFamily:L}}>incl. VAT</p><BO onClick={()=>{onAdd();setA(true);setTimeout(()=>setA(false),1200);}} label={a?"Added!":"Add to cart"} full/></div></div>);};

const SUP=({setCP})=>{const[f,setF]=useState({name:"",location:"",goal:"",phone:""});const[done,setDone]=useState(false);const[ld,setLd]=useState(false);const[er,setEr]=useState({});if(done)return(<PW t="" st=""><AI direction="scale"><div style={{textAlign:"center",maxWidth:500,margin:"0 auto"}}><div style={{width:80,height:80,background:"rgba(255,255,255,.05)",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 24px",fontSize:36,color:"#fff"}}>&#10003;</div><h2 style={{fontSize:32,fontWeight:700,color:"#fff",margin:"0 0 12px",fontFamily:F}}>You're in!</h2><p style={{color:"rgba(255,255,255,.4)",fontSize:16,margin:"0 0 32px",fontFamily:L}}>Welcome, {f.name}. Details sent via WhatsApp.</p><BP onClick={()=>setCP("home")} label="Back to home"/></div></AI></PW>);const fds=[{l:"Name",k:"name",ph:"Full name",t:"text"},{l:"Location",k:"location",ph:"e.g. Lekki Phase 1",t:"text"},{l:"Fitness goal",k:"goal",ph:"e.g. Lose weight",t:"text"},{l:"Phone",k:"phone",ph:"+234 800 000 0000",t:"tel"}];return(<PW t="Sign up" st="Get started in under 3 minutes"><div style={{maxWidth:440,margin:"0 auto"}}>{fds.map((x,i)=><AI key={x.k} delay={i*.08}><div style={{marginBottom:20}}><label style={{display:"block",fontSize:12,color:"rgba(255,255,255,.35)",marginBottom:6,fontFamily:L}}>{x.l}{x.k!=="goal"&&<span style={{color:"rgba(255,255,255,.2)"}}> *</span>}</label><input type={x.t} placeholder={x.ph} value={f[x.k]} onChange={e=>{setF({...f,[x.k]:e.target.value});if(er[x.k])setEr({...er,[x.k]:null});}} style={{width:"100%",padding:"14px 16px",background:"rgba(255,255,255,.03)",border:`1px solid ${er[x.k]?"rgba(255,100,100,.5)":"rgba(255,255,255,.08)"}`,color:"#fff",fontSize:15,outline:"none",boxSizing:"border-box",fontFamily:L}}/>{er[x.k]&&<p style={{color:"rgba(255,100,100,.7)",fontSize:12,marginTop:4,fontFamily:L}}>{er[x.k]}</p>}</div></AI>)}<AI delay={.35}><BP onClick={()=>{const e={};if(!f.name.trim())e.name="Required";if(!f.phone.trim())e.phone="Required";if(!f.location.trim())e.location="Required";if(Object.keys(e).length){setEr(e);return;}setEr({});setLd(true);setTimeout(()=>{sWA(f);setLd(false);setDone(true);},1000);}} label="Complete sign up" loading={ld} style={{width:"100%",marginTop:8}}/></AI></div></PW>);};

const CSP=()=>(<PW t="Book a consultation" st={`Schedule a call — \u20A6${fp(20000)} incl. VAT`}><AI><div style={{maxWidth:700,margin:"0 auto",textAlign:"center"}}><div style={{border:"1px solid rgba(255,255,255,.06)",overflow:"hidden",minHeight:500}}><iframe src={CU} width="100%" height="500" frameBorder="0" style={{border:"none",background:"#111"}} title="Calendly"/></div></div></AI></PW>);
